+    let commands = mgr.list_commands();
+    assert_eq!(commands.len(), 1);
+    assert_eq!(commands[0]["name"], "deploy");
+    assert_eq!(commands[0]["description"], "Deploy the app");
+    assert_eq!(commands[0]["source"], "extension");
+}
